// 1. Select by ID (Fastest, legacy method)
const header = document.getElementById('main-header');

// 2. Select the FIRST element that matches a CSS selector (Modern, flexible)
const submitBtn = document.querySelector('.btn-primary');
const firstInput = document.querySelector('form input[type="text"]');

// 3. Select ALL elements that match (Returns a NodeList)
const allLinks = document.querySelectorAll('a.nav-link');

// A NodeList is like an array, we can loop over it:
allLinks.forEach(link => link.style.color = 'blue');

